1	# Boot configuration for mininixos (BTRFS + LUKS)
2	#
3	# LUKS device "M" is declared by disko.nix (device path, allowDiscards).
4	# systemd stage 1 unlocks it with the passphrase in LUKS keyslot 0. Keyslot 2
5	# still holds the legacy Yubikey challenge-response secret (unused by systemd
6	# stage 1); re-enroll the key with `systemd-cryptenroll --fido2-device=auto`.
7	
8	{ pkgs, ... }:
9	{
10	  boot = {
11	    kernel.sysctl = {
12	      "vm.swappiness" = 5;
13	    };
14	
15	    supportedFilesystems = [ "btrfs" ];
16	
17	    # Must track linuxPackages_latest: the stable series (6.18) fails to
18	    # assemble the /data RAID5 (md rejects a valid superblock, -EINVAL).
19	    # Freeze risk is handled via autodefrag removal + watchdog instead.
20	    kernelPackages = pkgs.linuxPackages_latest;
21	    kernelParams = [
22	      "nohibernate"
23	      "amdgpu.runpm=0" # disable runtime PM — headless server, GPU must stay awake for Ollama
24	    ];
25	
26	    initrd = {
27	      supportedFilesystems = [ "btrfs" ];
28	      kernelModules = [
29	        "uas"
30	        "usbcore"
31	        "usb_storage"
32	        "usbhid"
33	        "vfat"
34	        "nls_cp437"
35	        "nls_iso8859_1"
36	      ];
37	
38	      luks = {
39	        cryptoModules = [
40	          "aes"
41	          "xts"
42	          "sha512"
43	          "sha256"
44	
45	          "cbc"
46	          "hmac"
47	          "rng"
48	          "encrypted_keys"
49	
50	          "blowfish"
51	          "twofish"
52	          "serpent"
53	          "lrw"
54	          "af_alg"
55	          "algif_skcipher"
56	        ];
57	
58	        devices = {
59	          # disko sets: device, allowDiscards
60	          "M" = {
61	            preLVM = true;
62	          };
63	        };
64	      };
65	    };
66	
67	    loader = {
68	      efi = {
69	        canTouchEfiVariables = false;
70	        efiSysMountPoint = "/boot";
71	      };
72	      grub = {
73	        enable = true;
74	        device = "nodev";
75	        efiSupport = true;
76	        efiInstallAsRemovable = true;
77	        enableCryptodisk = true;
78	      };
79	    };
80	  };
81	}
